## 04.2_branch_point_manual.R
## Branch-point analysis — Part 2: positional mutational sensitivity around
## manually annotated and LaBranchoR-predicted branch points.
##
## Inputs:
##   results/analysis/04_branchpoint/04.1_processing_data/psi_df_bp_labranchor.txt
##     (generated by 04.1_branch_point_processing_data.R)
##
## Outputs:
##   figures/04_branchpoint/04.2_branch_point_manual/
##     bp_heatmap_mut_type.png
##     bp_wt_nt_by_region.png
##     bp_violin_by_region.png
##     sub_bp_boxplot.png
##     heatmap_manual.pdf
##     violin_bp_manual.png
##     violin_bp_manual_zoom.png
##   results/analysis/04_branchpoint/04.2_branch_point_manual/
##     count_sub_del1_PPT.tsv

library(data.table)
library(dplyr)
library(ggplot2)
library(tibble)
library(scales)
library(tidyr)
library(stringr)
library(rstatix)
library(ggpubr)
library(here)

source(here("analysis", "config.R"))

plot_dir    <- here("figures", "04_branchpoint", "04.2_branch_point_manual")
results_dir <- here("results", "analysis", "04_branchpoint", "04.2_branch_point_manual")
dir.create(plot_dir,    showWarnings = FALSE, recursive = TRUE)
dir.create(results_dir, showWarnings = FALSE, recursive = TRUE)

# Directory produced by 04.1
data_dir <- here("results", "analysis", "04_branchpoint", "04.1_processing_data")

palette <- c(
  pos5 = "#8B0000",   # most positive
  pos4 = "firebrick",
  pos3 = "#F88379",
  pos2 = "#F4C2C2",
  pos1 = "#FFD1DC",
  mid  = "gray70",   # -0.5 to 0.5
  neg1 = "#E0FFFF",
  neg2 = "#AFDBF5",
  neg3 = "#7AAED4",
  neg4 = "steelblue",  #"#4A90E2", "#2c7fb8",
  neg5 = "#00416A"  # most negative
)

# ── Load files ────────────────────────────────────────────────────────────────
psi_df_bp <- fread(file.path(data_dir, "psi_df_bp_labranchor.txt"), sep = "\t")

psi_df_bp <- psi_df_bp %>%
  filter(!is.na(psi) & !is.na(wt_psi) & start < 67) %>%
  select(exon_id,variant_id,psi,delta_psi,delta_logit,significant,wt,mut,mut_type,coord_rel,label) %>%
  mutate(
    delta_bin = case_when(
      significant != "yes"                      ~ "mid",
      delta_logit <  -3                         ~ "neg5",
      delta_logit >= -3   & delta_logit < -2    ~ "neg4",
      delta_logit >= -2   & delta_logit < -1    ~ "neg3",
      delta_logit >= -1   & delta_logit < -0.5  ~ "neg2",
      delta_logit >= -0.5   & delta_logit < 0   ~ "neg1",
      delta_logit > 0 & delta_logit <= 0.5      ~ "pos1",
      delta_logit > 0.5  & delta_logit <= 1     ~ "pos2",
      delta_logit >  1  & delta_logit <= 2      ~ "pos3",
      delta_logit >  2  & delta_logit <= 3      ~ "pos4",
      delta_logit >  3                          ~ "pos5",
      TRUE                                      ~ "mid"   # safety
    ),
    delta_bin = factor(delta_bin, levels = names(palette)),
    mut_type  = ifelse(mut_type == 'sub', 'Sub', mut_type),
    mut_type  = factor(mut_type, levels = c('Sub', '∆1nt', '∆3nt', '∆6nt')),
    mut       = factor(mut, levels = c("∆6nt", "∆3nt", "∆1nt", "A", "G", "C", "U")),
    delta_bin = factor(delta_bin, levels = c("mid", "pos5", "pos4", "pos3", "pos2", "pos1",
                                             "neg5", "neg4", "neg3", "neg2", "neg1"))
  )

table_pos <- psi_df_bp %>%
  group_by(coord_rel, label) %>%
  summarise(n_exon = n_distinct(exon_id), .groups = "drop")

pos_ok <- table_pos$coord_rel[table_pos$n_exon > 15]

# ── Plot 1: BP heatmap by mut_type (manual exons) ────────────────────────────
p_bp_heatmap_mut_type <- ggplot(
  psi_df_bp %>% filter(coord_rel %in% pos_ok & label == 'manual'),
  aes(x = coord_rel - 6, fill = delta_bin)
) +
  geom_bar(position = "fill", width = 1) +
  scale_y_continuous(
    breaks = c(0, 0.5, 1),
    labels = percent_format(accuracy = 1, suffix = ""),
    name   = "Percentage of variants"
  ) +
  scale_fill_manual(
    values = palette,
    breaks = names(palette),
    name = expression(Delta*LogitPSI)
  ) +
  labs(y = "Percentage of variants") +
  geom_vline(xintercept = c(-6.5, 1.5), linewidth = 0.3, linetype = 'dashed') +
  scale_x_continuous(breaks = c(-40, -20, -6, 0, 10, 30),
                     labels = c('-40', '-20', '-6', 'A', '+10', '+30')) +
  theme_minimal() +
  theme(
    plot.background  = element_rect(color = NA),
    panel.grid.major = element_blank(),
    panel.grid.minor = element_blank(),
    axis.ticks       = element_line(color = 'black', linewidth = 0.5),
    axis.line        = element_line(color = 'black', linewidth = 0.5),
    axis.text        = element_text(size = 10, color = 'black', family = 'Helvetica'),
    axis.text.x      = element_text(size = 10, color = 'black', family = 'Helvetica'),
    axis.title.x     = element_blank(),
    axis.title.y     = element_text(size = 10, color = 'black', family = 'Helvetica'),
    legend.position  = 'none',
    strip.text       = element_text(size = 10, color = 'black', family = 'Helvetica')
  ) +
  facet_grid(rows = vars(mut_type))

ggsave(file.path(plot_dir, "bp_heatmap_mut_type.png"),
       plot = p_bp_heatmap_mut_type, height = 8, width = 10)

psi_df_bp <- psi_df_bp %>%
  mutate(region_intron_up = case_when(
    coord_rel %in% 1:7 ~ 'BP',
    coord_rel < 1 ~ 'before BP',
    coord_rel > 7 ~ 'PPT'
  ),
  mut_v2 = case_when(
    mut_type %in% c('∆3nt', '∆6nt') ~ mut,
    mut_type == 'Sub'  ~ paste0(wt, '>', mut),
    mut_type == '∆1nt' ~ paste0('∆', wt)
  ),
  region_intron_up = factor(region_intron_up, levels = c('before BP', 'BP', 'PPT')))

# ── Plot 2: WT nucleotide bar by region × mut_type ────────────────────────────
p_bp_wt_nt <- ggplot(
  psi_df_bp %>% filter(mut_type %in% c('Sub', '∆1nt')),
  aes(x = wt, fill = delta_bin)
) +
  geom_bar(position = "fill") +
  scale_y_continuous(
    name   = "Percentage of variants",
    breaks = c(0, 0.5, 1),
    labels = c(0, 50, 100)
  ) +
  scale_fill_manual(
    values = palette,
    breaks = names(palette),
    name = expression(Delta*LogitPSI)
  ) +
  labs(x = "WT nt") +
  theme_minimal() +
  theme(
    plot.background  = element_rect(color = NA),
    panel.grid.major = element_blank(),
    panel.grid.minor = element_blank(),
    axis.ticks       = element_line(color = 'black', linewidth = 0.5),
    axis.line        = element_line(color = 'black', linewidth = 0.5),
    axis.text        = element_text(size = 10, color = 'black', family = 'Helvetica'),
    axis.title       = element_text(size = 10, color = 'black', family = 'Helvetica'),
    legend.text      = element_text(size = 10, color = 'black', family = 'Helvetica'),
    legend.title     = element_text(size = 10, color = 'black', family = 'Helvetica'),
    strip.text       = element_text(size = 10, color = 'black', family = 'Helvetica'),
    legend.position  = 'none'
  ) +
  facet_grid(rows = vars(region_intron_up), cols = vars(mut_type),
             scales = 'free_x', space = 'free_x')

ggsave(file.path(plot_dir, "bp_wt_nt_by_region.png"),
       plot = p_bp_wt_nt, height = 6, width = 5)

# ── Table: Sub + ∆1nt effect counts in PPT region ────────────────────────────
count_sub_del1 <- psi_df_bp %>%
  filter(mut_type %in% c('Sub', '∆1nt') & !is.na(delta_logit) & region_intron_up == 'PPT') %>%
  mutate(delta_bin = case_when(
    delta_bin == 'mid'            ~ 'mid',
    grepl('pos', delta_bin)       ~ 'pos',
    grepl('neg', delta_bin)       ~ 'neg',
  )) %>%
  group_by(mut_type, wt, delta_bin) %>%
  summarise(n_var = n(), .groups = "drop")

fwrite(count_sub_del1, file.path(results_dir, "count_sub_del1_PPT.tsv"), sep = "\t")

# ── Plot 3: Violin ∆LogitPSI by region × mut_type ────────────────────────────
p_bp_violin_region <- ggplot(psi_df_bp, aes(x = region_intron_up, y = delta_logit,
                                             fill = region_intron_up)) +
  geom_violin(linewidth = 0.2, alpha = 0.5) +
