  theme_minimal() +
  theme(
    plot.background  = element_rect(color = NA),
    panel.grid.major = element_blank(),
    panel.grid.minor = element_blank(),
    axis.ticks       = element_line(color = 'black', linewidth = 0.5),
    axis.line        = element_line(color = 'black', linewidth = 0.5),
    axis.text        = element_text(size = 10, color = 'black', family = 'Helvetica'),
    axis.title.x     = element_blank(),
    axis.title.y     = element_text(size = 10, color = 'black', family = 'Helvetica'),
    legend.text      = element_text(size = 10, color = 'black', family = 'Helvetica'),
    legend.title     = element_text(size = 10, color = 'black', family = 'Helvetica'),
    strip.text.y     = element_text(size = 10, color = 'black', family = 'Helvetica'),
    strip.text.x     = element_blank(),
    legend.position  = 'none'
  ) +
  facet_grid(rows = vars(mut_type), cols = vars(region_intron_up),
             scales = 'free_x', space = 'free_x')

ggsave(file.path(plot_dir, "bp_violin_by_region.png"),
       plot = p_bp_violin_region, height = 8, width = 6)

nrow(psi_df_bp[psi_df_bp$region_intron_up == 'before BP' & abs(delta_logit) > 0.5 & psi_df_bp$significant == 'yes',]) /
  nrow(psi_df_bp[psi_df_bp$region_intron_up == 'before BP',])
nrow(psi_df_bp[psi_df_bp$region_intron_up == 'BP' & abs(delta_logit) > 0.5 & psi_df_bp$significant == 'yes',]) /
  nrow(psi_df_bp[psi_df_bp$region_intron_up == 'BP',])
nrow(psi_df_bp[psi_df_bp$region_intron_up == 'PPT' & abs(delta_logit) > 0.5 & psi_df_bp$significant == 'yes',]) /
  nrow(psi_df_bp[psi_df_bp$region_intron_up == 'PPT',])

sub_bp <- psi_df_bp %>%
  filter(mut_type == 'Sub' & coord_rel %in% 1:7 & label == 'manual') %>%
  mutate(wt = ifelse(wt == 'T', 'U', wt),
         mut_v2 = paste0(wt, '>', mut))

nt_pal_light <- c(
  A = "#A9E6C7",
  U = "#F7B3B3",
  G = "#6B6B6B",
  C = "#A9C6FF"
)

