# ── Heatmap and violin: mutational signature at BP positions ──────────────────

delta_colours <- colorRampPalette(
  c("#2171B5", "#4292C6", "#A6CEE3", "white", "#FDAEAE", "#FB6A4A", "#EF3B2C")
)(200)

label_consensus <- data.frame(pos = 1:7,
                               consensus = c("Y", "N", "Y", "U", "R", "A", "Y"))

plot_heatmap <- function(df,
                         x         = coord_rel,
                         y         = exon_id,
                         fill      = median,
                         label_col = NULL,
                         pseudo_log = FALSE,
                         sigma     = 10,
                         limits    = c(-100, 100),
                         x_labels  = NULL,
                         legend    = FALSE,
                         facet_row = NULL,
                         facet_col = NULL) {
  fill_scale <- if (pseudo_log) {
    scale_fill_gradientn(
      colours = delta_colours,
      limits = c(-100, 100),
      breaks = c(-100, -50, -25, -5, 0, 5, 25, 50, 100),
      trans  = scales::pseudo_log_trans(sigma = 10),
      oob    = scales::squish,
      guide = guide_colourbar(
        barwidth  = unit(5, "cm"),
        barheight = unit(3, "mm")
      ),
      na.value = "grey60",
    )
  } else {
    scale_fill_gradientn(colours = delta_colours, limits = limits,
                         oob = squish, guide = "colourbar", na.value = "grey80")
  }
  p <- ggplot(df, aes(x = as.factor({{ x }}), y = {{ y }}, fill = {{ fill }})) +
    geom_tile() + fill_scale +
    theme_minimal() +
    theme(panel.grid = element_blank(), axis.ticks = element_blank(),
          axis.title = element_blank(), axis.text = element_blank(),
          legend.text  = element_text(size = 10, color = "black"),
          legend.title = element_text(size = 10, color = "black"),
          plot.background = element_rect(color = NA),
          strip.text.y = element_blank(),
          legend.position = if (legend) "bottom" else "none") +
    labs(fill = "Median ∆PSI Substitution")
  if (!is.null(label_col))
    p <- p + geom_text(aes(label = .data[[label_col]]), size = 5)
  if (!is.null(x_labels))
    p <- p + scale_x_discrete(breaks = x_labels$pos, labels = x_labels$consensus)
  if (!is.null(facet_row) || !is.null(facet_col))
    p <- p + facet_grid(rows = facet_row, cols = facet_col,
                        scales = "free", space = "free")
  p
}

plot_violin <- function(df, x = coord_rel, y = delta_psi,
                        x_labels = NULL, faceted = FALSE, facet_var = mut_type) {
  p <- ggplot(df, aes(x = as.factor({{ x }}), y = {{ y }})) +
    geom_violin(color = "black", linewidth = 0.2, width = 1,
                alpha = 0.5, fill = "#A6CEE3") +
    geom_boxplot(color = "black", linewidth = 0.2, width = 0.1,
                 outliers = FALSE, fill = "#A6CEE3") +
    stat_summary(aes(group = 1), fun = median, geom = "line",
                 linewidth = 0.4, color = "black") +
    theme_minimal() +
    theme(axis.line    = element_line(color = "black"),
          axis.ticks   = element_line(color = "black"),
          axis.text    = element_text(size = 10, color = "black", family = "Helvetica"),
          axis.title.x = element_blank(),
          axis.text.y  = element_text(size = 10, color = "black", family = "Helvetica"),
          panel.border = element_blank(), panel.grid = element_blank(),
          legend.position = "none") +
    ylab("∆PSI")
  if (!is.null(x_labels))
    p <- p + scale_x_discrete(breaks = x_labels$pos, labels = x_labels$consensus)
  if (faceted) p <- p + facet_grid(rows = vars({{ facet_var }}))
  p
}

cluster_exons <- function(df, k = 2) {
  mat <- df %>%
    filter(coord_rel %in% 1:7, mut_type == "sub", order_bp == 1) %>%
    group_by(exon_id, coord_rel) %>%
    summarise(median = median(delta_logit, na.rm = TRUE), .groups = "drop") %>%
    pivot_wider(names_from = coord_rel, values_from = median) %>%
    column_to_rownames("exon_id") %>%
    as.matrix()
  mat[is.na(mat)] <- 0
  hc <- hclust(dist(mat, method = "manhattan"), method = "ward.D2")
  data.frame(exon_id = hc$labels, order = hc$order,
             cluster = cutree(hc, k = k)) %>%
    arrange(cluster, order) %>%
    mutate(exon_id = factor(exon_id, levels = exon_id))
}

# Reload with all columns needed for clustering and heatmap (psi_df_bp
# above was filtered to start < 67 and had columns dropped)
psi_df_bp_full <- fread(file.path(data_dir, "psi_df_bp_labranchor.txt"), sep = "\t")
psi_df_bp_full$mut_type <- factor(psi_df_bp_full$mut_type,
                                   levels = c("sub", "∆1nt", "∆3nt", "∆6nt"))

order_row_manual <- psi_df_bp_full %>%
  filter(label == "manual") %>%
  cluster_exons(k = 1)

bp_median_manual <- psi_df_bp_full %>%
  filter(label == "manual", mut_type == "sub") %>%
  group_by(exon_id, start, coord_rel, wt, wt_psi, label, order_bp) %>%
  summarise(median = median(delta_psi, na.rm = TRUE), .groups = "drop") %>%
  mutate(exon_id = factor(exon_id, levels = levels(order_row_manual$exon_id))) %>%
  left_join(order_row_manual, by = "exon_id")

psi_df_bp_manual <- psi_df_bp_full %>%
  filter(label == "manual") %>%
  mutate(exon_id = factor(exon_id, levels = levels(order_row_manual$exon_id)))

p_heatmap_manual <- plot_heatmap(bp_median_manual, pseudo_log = TRUE,
                                  x_labels = label_consensus, legend = TRUE)

p_violin_manual <- plot_violin(
  psi_df_bp_manual %>% filter(coord_rel < 60, mut_type == "sub"),
  x_labels = label_consensus)

p_violin_manual_zoom <- plot_violin(
  psi_df_bp_manual %>% filter(coord_rel %in% -3:20, mut_type == "sub"),
  y = delta_psi, x_labels = label_consensus)

ggsave(file.path(plot_dir, "heatmap_manual.pdf"),
       p_heatmap_manual, height = 60, width = 40, limitsize = FALSE)
ggsave(file.path(plot_dir, "violin_bp_manual.png"),
       p_violin_manual, height = 4, width = 30, limitsize = FALSE)
ggsave(file.path(plot_dir, "violin_bp_manual_zoom.png"),
       p_violin_manual_zoom, height = 10, width = 10, limitsize = FALSE)

